type HeroSkyCloudSvgProps = {
  className?: string
  idSuffix: string
}

// TODO: replace this with your full cloud PNG base64 payload.
const HERO_CLOUD_BASE64 =
  'data:image/png;base64,'

export function HeroSkyCloudSvg({ className, idSuffix }: HeroSkyCloudSvgProps) {
  const patternId = `hero-cloud-pattern-${idSuffix}`
  const imageId = `hero-cloud-image-${idSuffix}`

  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width="1244"
      height="447"
      viewBox="0 0 1244 447"
      fill="none"
      aria-hidden
      className={className}
    >
      <path fill={`url(#${patternId})`} d="M0 0h1244v447H0z" style={{ mixBlendMode: 'screen' }} />
      <defs>
        <pattern id={patternId} width="1" height="1" patternContentUnits="objectBoundingBox">
          <use href={`#${imageId}`} transform="scale(.0008 .00224)" />
        </pattern>
        <image
          id={imageId}
          width="1244"
          height="447"
          data-name="image.png"
          href={HERO_CLOUD_BASE64}
          preserveAspectRatio="none"
        />
      </defs>
    </svg>
  )
}
